// -R Stat counter card -R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R-R
function StatCard({ value, suffix, label, display, index }: {
  value: number; suffix: string; label: string; display?: string; index: number;
}) {
  const { ref, count } = useCounter(value);
  return (
    <motion.div variants={fadeUp} className="flex flex-col items-center">
      <motion.span
        ref={ref}
        className="text-4xl sm:text-5xl font-black text-white tabular-nums"
        initial={{ scale: 0.8 }}
        whileInView={{ scale: 1 }}
        viewport={{ once: true }}
        transition={{ delay: index * 0.1 + 0.3, type: "spring", stiffness: 200 }}
      >
        {display ?? count}{suffix}
      </motion.span>
      <span className="text-sm text-primary-foreground/65 font-medium mt-1">{label}</span>
    </motion.div>
  );
}

